solution_code:
#include <iostream>

int main()
{
    constexpr bool debugMode { true };

    int n {};
    std::cin >> n;

    if constexpr (debugMode)
        std::cout << "Debug: " << n << '\n';

    std::cout << "Value: " << n << '\n';

    return 0;
}

