solution_code:
#include <iostream>

constexpr int platformBits { 64 };

void printSizeInfo()
{
    if constexpr (platformBits == 64)
        std::cout << "Platform: 64-bit\n";
    else
        std::cout << "Platform: 32-bit\n";
}

int main()
{
    printSizeInfo();
    return 0;
}
